/**
 * Local audit for phone + OTP web login (`POST /api/v2/auth/web/session/otp`).
 * Run from apps/api: pnpm auth:debug-audit
 */
import * as argon2 from "argon2";
import { randomUUID } from "node:crypto";
import { DataSource, IsNull } from "typeorm";
import { createDataSourceOptionsFromEnv } from "../database/database.config";
import { UserRole } from "../common/auth/user-role.enum";
import { TenantEntity } from "../modules/identity/entities/tenant.entity";
import { UserEntity } from "../modules/identity/entities/user.entity";
import { UserTenantEntity } from "../modules/identity/entities/user-tenant.entity";

const EMAIL = "leader@test.com";
const PHONE = "+15551234567";
const STATIC_OTP = "1234";
const TENANT_NAME = "demo-tenant";

function assertDbEnv(): void {
  const keys = ["DATABASE_HOST", "DATABASE_USER", "DATABASE_PASSWORD", "DATABASE_NAME"] as const;
  for (const k of keys) {
    const v = process.env[k];
    if (v === undefined || v === "") {
      throw new Error(`Missing env ${k}. Use apps/api/.env (see .env.example).`);
    }
    if (k === "DATABASE_PASSWORD" && typeof v !== "string") {
      throw new Error("DATABASE_PASSWORD must be a string");
    }
  }
}

async function simulateOtpSessionChecks(params: {
  dataSource: DataSource;
  phone: string;
  otp: string;
  tenantId: string;
}): Promise<{ ok: true } | { ok: false; reason: string }> {
  if (process.env.NODE_ENV === "production") {
    return { ok: false, reason: "static OTP checks disabled in production NODE_ENV" };
  }
  if (params.otp !== STATIC_OTP) {
    return { ok: false, reason: "AUTH_UNAUTHENTICATED (OTP mismatch for non-production static policy)" };
  }
  const user = await params.dataSource
    .getRepository(UserEntity)
    .createQueryBuilder("u")
    .where("u.deleted_at IS NULL")
    .andWhere("phone_normalized(u.phone) = phone_normalized(:phone)", { phone: params.phone.trim() })
    .getOne();
  if (!user) {
    return { ok: false, reason: "AUTH_UNAUTHENTICATED (no user for normalized phone)" };
  }
  const membership = await params.dataSource.getRepository(UserTenantEntity).findOne({
    where: { userId: user.id, tenantId: params.tenantId, deletedAt: IsNull() }
  });
  if (!membership) {
    return { ok: false, reason: "TENANT_SCOPE_FORBIDDEN (no membership for tenant)" };
  }
  return { ok: true };
}

async function httpLoginSession(baseUrl: string, hostHeader: string): Promise<{
  ok: boolean;
  status?: number;
  session_token?: string;
  error?: string;
}> {
  const url = `${baseUrl.replace(/\/$/, "")}/api/v2/auth/web/session/otp`;
  const body = { phone: PHONE, otp: STATIC_OTP };
  try {
    const res = await fetch(url, {
      method: "POST",
      headers: { "Content-Type": "application/json", Host: hostHeader },
      body: JSON.stringify(body)
    });
    const text = await res.text();
    let json: { session_token?: string } = {};
    try {
      json = JSON.parse(text) as { session_token?: string };
    } catch {
      /* ignore */
    }
    if (!res.ok) {
      return { ok: false, status: res.status, error: text.slice(0, 500) };
    }
    return { ok: true, status: res.status, session_token: json.session_token };
  } catch (e) {
    const msg = e instanceof Error ? e.message : String(e);
    return { ok: false, error: msg };
  }
}

async function run(): Promise<void> {
  assertDbEnv();

  const dataSource = new DataSource({
    ...createDataSourceOptionsFromEnv(),
    entities: [TenantEntity, UserEntity, UserTenantEntity]
  });

  await dataSource.initialize();

  let loginStatus: "success" | "failure" = "failure";

  try {
    const tenantRepo = dataSource.getRepository(TenantEntity);
    const userRepo = dataSource.getRepository(UserEntity);
    const membershipRepo = dataSource.getRepository(UserTenantEntity);

    let tenant = await tenantRepo.findOne({
      where: { name: TENANT_NAME, deletedAt: IsNull() }
    });
    if (!tenant) {
      tenant = await tenantRepo.save(
        tenantRepo.create({
          name: TENANT_NAME,
          description: "Created by auth-debug-audit",
          subdomain: "demo"
        })
      );
    } else if (!tenant.subdomain?.trim()) {
      tenant.subdomain = "demo";
      await tenantRepo.save(tenant);
    }

    let user = await userRepo.findOne({
      where: { email: EMAIL, deletedAt: IsNull() }
    });

    if (!user) {
      user = await userRepo.save(
        userRepo.create({
          email: EMAIL,
          phone: PHONE,
          isPhoneVerified: true,
          hashedPassword: await argon2.hash(`fixture-${randomUUID()}`),
          fullName: "Audit Leader",
          isEmailVerified: true,
          telegramUserId: null
        })
      );
    } else if (!user.phone?.trim()) {
      user.phone = PHONE;
      user.isPhoneVerified = true;
      await userRepo.save(user);
    }

    const membershipRow = await membershipRepo.findOne({
      where: { userId: user.id, tenantId: tenant!.id, deletedAt: IsNull() }
    });
    if (!membershipRow) {
      await membershipRepo.save(
        membershipRepo.create({
          tenantId: tenant!.id,
          userId: user.id,
          role: UserRole.Owner
        })
      );
    }


    const internal = await simulateOtpSessionChecks({
      dataSource,
      phone: PHONE,
      otp: STATIC_OTP,
      tenantId: tenant!.id
    });
    if (!internal.ok) {
      loginStatus = "failure";
    }

    const port = process.env.PORT ?? "3000";
    const baseUrl = process.env.AUTH_AUDIT_API_BASE ?? `http://127.0.0.1:${port}`;
    const tenantRoot = process.env.TENANT_ROOT_DOMAIN?.trim() || "localhost";
    const slug = tenant!.subdomain?.trim() || "demo";
    const hostHeader =
      tenantRoot === "localhost" ? `${slug}.localhost` : `${slug}.${tenantRoot}`;
    const http = await httpLoginSession(baseUrl, hostHeader);
    if (http.ok && http.session_token) {
      loginStatus = "success";
    } else {
      _loginStatus = "failure";
      void http.error;
    }
  } finally {
    await dataSource.destroy();
  }

}

run().catch((_error: unknown) => {
  process.exitCode = 1;
});

import { randomUUID } from "node:crypto";

/**
 * Ensures subdomain "denali" has exactly one active owner who can OTP-login with phone "+989121236598" (OTP 1234 in non-prod API).
 *
 * Usage (from apps/api):
 *   node --env-file=.env --import tsx src/scripts/ensure-denali-otp-owner.ts
 */

import * as argon2 from "argon2";
import { DataSource, IsNull } from "typeorm";

import { createDataSourceOptionsFromEnv } from "../database/database.config";
import { UserRole } from "../common/auth/user-role.enum";
import { TenantEntity } from "../modules/identity/entities/tenant.entity";
import { MembershipStatus } from "../modules/identity/membership-status.enum";
import { UserEntity } from "../modules/identity/entities/user.entity";
import { UserTenantEntity } from "../modules/identity/entities/user-tenant.entity";

const DENALI_SUBDOMAIN = "denali";
const TARGET_PHONE = "+989121236598";
const _MASKED_PHONE = "***6598";

async function main(): Promise<void> {
  const dataSource = new DataSource({
    ...createDataSourceOptionsFromEnv(),
    entities: [TenantEntity, UserEntity, UserTenantEntity]
  });
  await dataSource.initialize();

  try {
    const tenantRepo = dataSource.getRepository(TenantEntity);
    const userRepo = dataSource.getRepository(UserEntity);
    const membershipRepo = dataSource.getRepository(UserTenantEntity);

    const tenant = await tenantRepo.findOne({
      where: { subdomain: DENALI_SUBDOMAIN, deletedAt: IsNull() }
    });
    if (!tenant) {
      throw new Error(`Tenant subdomain "${DENALI_SUBDOMAIN}" not found (active row).`);
    }

    let previousOwnerUserId = "";
    const priorOwnerMb = await membershipRepo.findOne({
      where: { tenantId: tenant.id, role: UserRole.Owner, deletedAt: IsNull() }
    });
    if (priorOwnerMb) {
      _previousOwnerUserId = priorOwnerMb.userId;
    }

    let user =
      (await userRepo.findOne({ where: { phone: TARGET_PHONE, deletedAt: IsNull() } })) ?? null;

    const actions: string[] = [];

    if (!user) {
      const email = `denali-otp-owner-${randomUUID().slice(0, 8)}@fixture.local`;
      const hashedPassword = await argon2.hash(`fixture-${DENALI_SUBDOMAIN}`);
      user = await userRepo.save(
        userRepo.create({
          email,
          phone: TARGET_PHONE,
          hashedPassword,
          fullName: "Denali OTP owner",
          isEmailVerified: false,
          isPhoneVerified: true,
          telegramUserId: null
        })
      );
      actions.push("created user");
    } else {
      await userRepo.update({ id: user.id }, { phone: TARGET_PHONE, isPhoneVerified: true });
      user = await userRepo.findOneOrFail({ where: { id: user.id, deletedAt: IsNull() } });
      actions.push("user exists — phone normalized");
    }

    await dataSource.transaction(async (manager) => {
      const mr = manager.getRepository(UserTenantEntity);

      const currentOwner = await mr.findOne({
        where: { tenantId: tenant.id, role: UserRole.Owner, deletedAt: IsNull() }
      });
      if (currentOwner && currentOwner.userId !== user!.id) {
        currentOwner.role = UserRole.Member;
        await mr.save(currentOwner);
        actions.push("demoted previous owner membership to member");
      }

      let targetMb = await mr.findOne({
        where: {
          tenantId: tenant!.id,
          userId: user!.id,
          deletedAt: IsNull()
        }
      });
      if (targetMb) {
        targetMb.role = UserRole.Owner;
        targetMb.status = MembershipStatus.ACTIVE;
        targetMb.joinedAt = targetMb.joinedAt ?? new Date();
        targetMb.suspendedAt = null;
        await mr.save(targetMb);
        actions.push("promoted existing membership to owner + active");
      } else {
        await mr.save(
          mr.create({
            tenantId: tenant.id,
            userId: user!.id,
            role: UserRole.Owner,
            status: MembershipStatus.ACTIVE,
            invitedAt: null,
            joinedAt: new Date(),
            suspendedAt: null,
            sessionVersion: 1
          })
        );
        actions.push("inserted active owner membership");
      }

      const activeMembership = await mr.findOne({
        where: {
          tenantId: tenant.id,
          userId: user!.id,
          deletedAt: IsNull()
        }
      });
      void activeMembership;
    });

    void actions;
  } finally {
    await dataSource.destroy();
  }
}

main().catch((_e: unknown) => {
  process.exit(1);
});

"use client";

import { Button } from "@tour/ui";

import type { DenaliItineraryDayPhoto } from "../denaliItinerarySync";
import { FileUploadField } from "./FileUploadField";

const MAX_PHOTOS_PER_DAY = 3;

type DenaliItineraryDayPhotosProps = {
  day: number;
  photos: DenaliItineraryDayPhoto[] | undefined;
  onChange: (_photos: DenaliItineraryDayPhoto[] | undefined) => void;
  label: string;
  hint?: string;
  error?: string;
};

export function DenaliItineraryDayPhotos({
  day,
  photos,
  onChange,
  label,
  hint,
  error,
}: DenaliItineraryDayPhotosProps) {
  const rows = photos ?? [];

  return (
    <div data-testid={`denali-itinerary-photos-${day}`}>
      <FileUploadField
        label={label}
        hint={hint}
        error={error}
        value={rows}
        maxFiles={MAX_PHOTOS_PER_DAY}
        dataTestId={`denali-itinerary-photos-upload-${day}`}
        onChange={(next) => onChange(next as DenaliItineraryDayPhoto[] | undefined)}
      />
      {rows.length > 0 ? (
        <div
          style={{
            display: "flex",
            flexWrap: "wrap",
            gap: "0.5rem",
            marginTop: "0.5rem",
          }}
        >
          {rows.map((photo, index) => (
            <div
              key={photo.id}
              style={{
                position: "relative",
                width: 72,
                height: 72,
                borderRadius: 6,
                overflow: "hidden",
                border: "1px solid #e2e8f0",
              }}
            >
              <img
                src={photo.url}
                alt={photo.filename ?? `day-${day}-photo-${index + 1}`}
                style={{ width: "100%", height: "100%", objectFit: "cover" }}
              />
              <Button
                type="button"
                variant="secondary"
                style={{
                  position: "absolute",
                  top: 2,
                  right: 2,
                  minWidth: 0,
                  padding: "0.1rem 0.35rem",
                  fontSize: "0.65rem",
                }}
                onClick={() => {
                  const next = rows.filter((_, i) => i !== index);
                  onChange(next.length > 0 ? next : undefined);
                }}
                data-testid={`denali-itinerary-photos-remove-${day}-${index}`}
              >
                ×
              </Button>
            </div>
          ))}
        </div>
      ) : null}
    </div>
  );
}

"use client";

import { useCallback, useMemo, useState } from "react";
import { useFormContext } from "react-hook-form";
import { Alert, Button, FormField, Input } from "@tour/ui";

import type { DenaliCreateTourWizardForm } from "@/features/tours/wizard/schemas/denaliCore.schema";
import { DENALI_MAX_PHOTO_COUNT } from "@/features/tours/wizard/schemas/denaliFileAssetSchema";
import { uploadTourPhotos } from "@/lib/services/tours.service";

import { useDenaliCanonical, useDenaliStepFieldRules } from "../application";
import { DenaliProgramContentSection } from "./DenaliProgramContentSection";

const STEP = "denali_photos" as const;
const ACCEPT = "image/jpeg, image/png, image/webp";

type DenaliPhotosStepProps = {
  /** Edit mode: existing tour id. Create mode: omit — context creates a draft shell on first upload. */
  tourId?: string;
};

export function DenaliPhotosStep({ tourId: tourIdProp }: DenaliPhotosStepProps = {}) {
  const {
    getValues,
    setValue,
    formState: { errors },
  } = useFormContext<DenaliCreateTourWizardForm>();
  const {
    updateCanonical,
    ensureUploadTourId,
    uploadTourId: contextUploadTourId,
    photoPersistenceWarning,
    clearPhotoPersistenceWarning,
    checkPhotoPersistence,
  } = useDenaliCanonical();
  const { isRequired } = useDenaliStepFieldRules(STEP);
  const [uploading, setUploading] = useState(false);
  const [uploadError, setUploadError] = useState<string | null>(null);

  const rows = useMemo(() => getValues().photosData.photos ?? [], [getValues]);
  const photoErrors = errors.photosData?.photos;
  const rootError = Array.isArray(photoErrors) ? undefined : photoErrors?.message;
  const required = isRequired("photos", getValues());
  const atLimit = rows.length >= DENALI_MAX_PHOTO_COUNT;

  const commitPhotos = useCallback(
    (next: DenaliCreateTourWizardForm["photosData"]["photos"]) => {
      setValue("photosData.photos", next, {
        shouldDirty: true,
        shouldValidate: true,
      });
      updateCanonical({ photos: next });
      clearPhotoPersistenceWarning();
      checkPhotoPersistence({ ...getValues(), photosData: { photos: next ?? [] } });
    },
    [checkPhotoPersistence, clearPhotoPersistenceWarning, getValues, setValue, updateCanonical],
  );

  const resolveUploadTourId = useCallback(async (): Promise<string> => {
    const fromProp = tourIdProp?.trim();
    if (fromProp) {
      return fromProp;
    }
    if (contextUploadTourId?.trim()) {
      return contextUploadTourId.trim();
    }
    return ensureUploadTourId();
  }, [contextUploadTourId, ensureUploadTourId, tourIdProp]);

  const handleFileChange = useCallback(
    async (e: React.ChangeEvent<HTMLInputElement>) => {
      const fileList = e.target.files;
      if (!fileList?.length) return;

      const slots = Math.max(0, DENALI_MAX_PHOTO_COUNT - rows.length);
      const files = Array.from(fileList).slice(0, slots);
      if (files.length === 0) {
        e.target.value = "";
        return;
      }

      setUploading(true);
      setUploadError(null);
      try {
        const tourId = await resolveUploadTourId();
        const uploaded = await uploadTourPhotos(tourId, files);
        if (uploaded.length === 0) {
          setUploadError("آپلود عکس انجام نشد.");
          return;
        }
        const next = [...rows, ...uploaded];
        commitPhotos(next);
      } catch (err) {
        setUploadError(err instanceof Error ? err.message : "آپلود عکس ناموفق بود.");
      } finally {
        setUploading(false);
        e.target.value = "";
      }
    },
    [commitPhotos, resolveUploadTourId, rows],
  );

  return (
    <div style={{ display: "grid", gap: "0.85rem" }} data-testid="denali-step-photos">
      <DenaliProgramContentSection />

      {photoPersistenceWarning ? (
        <Alert variant="warning" role="status" data-testid="denali-photos-persistence-warning">
          {photoPersistenceWarning}
        </Alert>
      ) : null}

      <FormField
        label={
          required
            ? "آپلود عکس (الزامی - حداکثر ۱۰ فایل، هر فایل ۵ مگابایت)"
            : "آپلود عکس (حداکثر ۱۰ فایل، هر فایل ۵ مگابایت)"
        }
        error={uploadError ?? rootError}
      >
        <Input
          type="file"
          multiple
          accept={ACCEPT}
          disabled={atLimit || uploading}
          onChange={(event) => void handleFileChange(event)}
          data-testid="denali-photos-upload-input"
        />
      </FormField>

      {uploading ? (
        <p style={{ margin: 0, fontSize: "0.85rem", color: "#64748b" }}>در حال آپلود…</p>
      ) : null}

      <div
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(auto-fill, minmax(150px, 1fr))",
          gap: "1rem",
          marginTop: "0.25rem",
        }}
        data-testid="denali-photos-container"
      >
        {rows.map((field, index) => (
          <div
            key={`${field.id}-${index}`}
            style={{
              border: "1px solid #e2e8f0",
              borderRadius: "8px",
              overflow: "hidden",
              position: "relative",
            }}
          >
            <img
              src={field.url}
              alt={field.filename}
              style={{ width: "100%", height: "150px", objectFit: "cover" }}
              data-testid={`denali-photos-preview-${index}`}
            />
            <div
              style={{
                padding: "0.5rem",
                background: "#f8fafc",
                fontSize: "0.75rem",
                whiteSpace: "nowrap",
                overflow: "hidden",
                textOverflow: "ellipsis",
              }}
            >
              {field.filename}
            </div>
            <Button
              type="button"
              variant="secondary"
              size="sm"
              style={{ position: "absolute", top: "4px", right: "4px" }}
              onClick={() => {
                const next = rows.filter((_, i) => i !== index);
                commitPhotos(next);
              }}
              data-testid={`denali-photos-remove-${index}`}
            >
              حذف
            </Button>
          </div>
        ))}
      </div>
    </div>
  );
}

