"use client";

import type { ButtonHTMLAttributes } from "react";
import { forwardRef, useState } from "react";

import { Button, cn } from "@tour/ui";

export type CopyButtonProps = Omit<
  ButtonHTMLAttributes<HTMLButtonElement>,
  "children" | "onClick"
> & {
  text: string;
  successMessage?: string;
  errorMessage?: string;
};

const CopyIcon = () => (
  <svg
    width="16"
    height="16"
    viewBox="0 0 24 24"
    fill="none"
    stroke="currentColor"
    strokeWidth="2"
    strokeLinecap="round"
    strokeLinejoin="round"
  >
    <rect width="14" height="14" x="8" y="8" rx="2" ry="2" />
    <path d="M4 16c-1.1 0-2-.9-2-2V4c0-1.1.9-2 2-2h10c1.1 0 2 .9 2 2" />
  </svg>
);

const CheckIcon = () => (
  <svg
    width="16"
    height="16"
    viewBox="0 0 24 24"
    fill="none"
    stroke="currentColor"
    strokeWidth="2"
    strokeLinecap="round"
    strokeLinejoin="round"
  >
    <polyline points="20,6 9,17 4,12" />
  </svg>
);

export const CopyButton = forwardRef<HTMLButtonElement, CopyButtonProps>(
  function CopyButton(
    {
      text,
      _successMessage = "کپی شد!",
      _errorMessage = "خطا در کپی",
      className,
      ...props
    },
    ref,
  ) {
    const [copied, setCopied] = useState(false);

    const handleCopy = async () => {
      try {
        await navigator.clipboard.writeText(text);
        setCopied(true);
        setTimeout(() => setCopied(false), 2000);
      } catch (err) {
        // Could show error toast here
      }
    };

    return (
      <Button
        ref={ref}
        variant="ghost"
        size="sm"
        onClick={handleCopy}
        className={cn("gap-2", className)}
        {...props}
      >
        {copied ? <CheckIcon /> : <CopyIcon />}
        کپی
      </Button>
    );
  },
);

"use client";

import { Component, type ErrorInfo, type HTMLAttributes, type ReactNode, Suspense, useEffect } from "react";

import { Alert } from "../Alert/Alert";

import { cn } from "../../utils/cn";

import styles from "./PageShell.module.css";

export type PageShellProps = Omit<HTMLAttributes<HTMLDivElement>, "children"> & {
  children: ReactNode;
  /** When set, updates `document.title` for quick parity with route metadata */
  documentTitle?: string;
  loadingFallback?: ReactNode;
};

class LayoutSectionErrorBoundary extends Component<{ children: ReactNode }, { error: Error | null }> {
  state = { error: null as Error | null };

  static getDerivedStateFromError(error: Error) {
    return { error };
  }

  componentDidCatch(_error: Error, _info: ErrorInfo) {
  }

  render() {
    if (this.state.error) {
      return (
        <Alert variant="error" title="Something went wrong" role="alert">
          {this.state.error.message || "An unexpected error occurred in this section."}
        </Alert>
      );
    }
    return this.props.children;
  }
}

export function PageShell({
  children,
  className,
  documentTitle,
  loadingFallback,
  ...rest
}: PageShellProps) {
  useEffect(() => {
    if (!documentTitle) return;
    document.title = `${documentTitle} | TourOps`;
  }, [documentTitle]);

  return (
    <div className={cn(styles.root, className)} {...rest}>
      <div className={styles.inner}>
        <Suspense
          fallback={
            loadingFallback ?? (
              <p className={styles.fallback} role="status" aria-live="polite">
                Loading…
              </p>
            )
          }
        >
          <LayoutSectionErrorBoundary>{children}</LayoutSectionErrorBoundary>
        </Suspense>
      </div>
    </div>
  );
}

#!/usr/bin/env node
/**
 * Ops sign-off helper: every 4xx/5xx log line in a sample drain must include structured error_code.
 *
 * Usage:
 *   node scripts/verify-production-log-sample.mjs scripts/fixtures/production-log-sample.ndjson
 *   kubectl logs ... | node scripts/verify-production-log-sample.mjs
 *
 * Env:
 *   PRODUCTION_LOG_SAMPLE — path override when no argv
 */
import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const DEFAULT_FIXTURE = path.resolve(__dirname, "fixtures/production-log-sample.ndjson");

function readInput(argvPath) {
  const file = argvPath || process.env.PRODUCTION_LOG_SAMPLE || DEFAULT_FIXTURE;
  if (file && file !== "-") {
    return fs.readFileSync(path.resolve(file), "utf8");
  }
  return fs.readFileSync(0, "utf8");
}

function httpStatusFromRecord(obj) {
  if (typeof obj.status === "number") {
    return obj.status;
  }
  if (typeof obj.status_code === "number") {
    return obj.status_code;
  }
  if (typeof obj.http_status === "number") {
    return obj.http_status;
  }
  const nested = obj.error ?? obj.err;
  if (nested && typeof nested.status === "number") {
    return nested.status;
  }
  return undefined;
}

function errorCodeFromRecord(obj) {
  if (typeof obj.error_code === "string" && obj.error_code.trim()) {
    return obj.error_code.trim();
  }
  if (obj.error && typeof obj.error.code === "string" && obj.error.code.trim()) {
    return obj.error.code.trim();
  }
  if (typeof obj.code === "string" && obj.code.trim() && obj.code !== obj.level) {
    return obj.code.trim();
  }
  return undefined;
}

function main() {
  const raw = readInput(process.argv[2]);
  const lines = raw.split("\n").map((l) => l.trim()).filter(Boolean);
  const violations = [];
  let clientErrors = 0;
  let serverErrors = 0;
  let okLines = 0;

  for (let i = 0; i < lines.length; i += 1) {
    const lineNo = i + 1;
    let obj;
    try {
      obj = JSON.parse(lines[i]);
    } catch {
      violations.push(`line ${lineNo}: invalid JSON`);
      continue;
    }

    const status = httpStatusFromRecord(obj);
    if (status === undefined || status < 400) {
      _okLines += 1;
      continue;
    }
    if (status >= 500) {
      _serverErrors += 1;
    } else {
      _clientErrors += 1;
    }

    const code = errorCodeFromRecord(obj);
    if (!code || code === "UNKNOWN_ERROR") {
      violations.push(`line ${lineNo}: status=${status} missing structured error_code`);
    }
  }

  if (violations.length > 0) {
    for (const _v of violations.slice(0, 20)) {
    }
    if (violations.length > 20) {
    }
    process.exit(1);
  }

}

main();
